healthcheck:
  test: ["CMD", "${1:curl}", "-f", "${2:http://localhost}"]
  interval: ${3:30s}
  timeout: ${4:10s}
  retries: ${5:3}
  start_period: ${6:5s}

deploy:
  replicas: ${1:3}
  resources:
    limits:
      cpus: "${2:0.5}"
      memory: ${3:512M}
  restart_policy:
    condition: ${4|on-failure,any,none|}

name: ${1:CI}

on:
  push:
    branches: [${2:main}]
  pull_request:
    branches: [${2:main}]

jobs:
  ${3:build}:
    runs-on: ${4:ubuntu-latest}
    steps:
      - uses: actions/checkout@v4
      - name: ${5:Run tests}
        run: ${6:echo "Hello"}

${1:job_name}:
  runs-on: ${2:ubuntu-latest}
  steps:
    - uses: actions/checkout@v4
    - name: ${3:Step name}
      run: ${4:echo "done"}

apiVersion: v1
kind: Pod
metadata:
  name: ${1:my-pod}
  labels:
    app: ${2:my-app}
spec:
  containers:
    - name: ${3:container}
      image: ${4:nginx:latest}
      ports:
        - containerPort: ${5:80}

apiVersion: apps/v1
kind: Deployment
metadata:
  name: ${1:my-deployment}
spec:
  replicas: ${2:3}
  selector:
    matchLabels:
      app: ${3:my-app}
  template:
    metadata:
      labels:
        app: ${3:my-app}
    spec:
      containers:
        - name: ${4:app}
          image: ${5:nginx:latest}
          ports:
            - containerPort: ${6:80}

apiVersion: v1
kind: Service
metadata:
  name: ${1:my-service}
spec:
  selector:
    app: ${2:my-app}
  ports:
    - protocol: TCP
      port: ${3:80}
      targetPort: ${4:8080}
  type: ${5|ClusterIP,NodePort,LoadBalancer|}

apiVersion: v1
kind: ConfigMap
metadata:
  name: ${1:my-config}
data:
  ${2:key}: ${3:value}

apiVersion: v1
kind: Secret
metadata:
  name: ${1:my-secret}
type: ${2:Opaque}
data:
  ${3:key}: ${4:base64encodedvalue}

apiVersion: v1
kind: PersistentVolumeClaim
metadata:
  name: ${1:my-pvc}
spec:
  accessModes:
    - ${2|ReadWriteOnce,ReadOnlyMany,ReadWriteMany|}
  resources:
    requests:
      storage: ${3:1Gi}
  storageClassName: ${4:standard}

apiVersion: v1
kind: ServiceAccount
metadata:
  name: ${1:my-sa}
  namespace: ${2:default}

version: '${1:3.8}'

services:
  ${2:web}:
    build: .
    ports:
      - "${3:3000}:${4:3000}"
    depends_on:
      - ${5:db}
    environment:
      DATABASE_URL: postgres://${6:user}:${7:pass}@${5:db}:5432/${8:mydb}

  ${5:db}:
    image: postgres:${9:16}
    volumes:
      - db_data:/var/lib/postgresql/data
    environment:
      POSTGRES_USER: ${6:user}
      POSTGRES_PASSWORD: ${7:pass}
      POSTGRES_DB: ${8:mydb}

volumes:
  db_data:
